// ─── Build PRISMA prompt for Ollama ───
const data = $input.all()[0].json;
const articles = data.articles || [];
const stats = data.stats || {};
const ris = data.ris || '';
const xlsx_base64 = data.xlsx_base64 || '';
const outputFolder = data.output_folder || '/desktop/review ultralab';

const question = (articles[0] && articles[0].question) || stats.question || '';
const criteria = (articles[0] && articles[0].criteria) || stats.criteria || '';

const total = stats.total || articles.length;
const included = stats.included || articles.filter(a => a.screening_decision === 'Include').length;
const excluded = stats.excluded || articles.filter(a => a.screening_decision === 'Exclude').length;
const maybe = stats.maybe || articles.filter(a => a.screening_decision === 'Maybe').length;
const with_pdf = stats.with_pdf || articles.filter(a => a.pdf_url).length;
const sources = stats.sources || [...new Set(articles.map(a => a.source).filter(Boolean))];
const clusters = stats.clusters || [...new Set(articles.map(a => a.cluster_label).filter(Boolean))];
const totalBeforeDedup = stats.total_before_dedup || total;
const duplicatesRemoved = stats.duplicates_removed || 0;

const topIncluded = articles
  .filter(a => a.screening_decision === 'Include')
  .sort((a, b) => (b.score || 0) - (a.score || 0))
  .slice(0, 10)
  .map(a => '- ' + (a.title || '').substring(0, 100) + ' (' + (a.year || '') + ')')
  .join('\n');

const clusterSummary = clusters.map(label => {
  const count = articles.filter(a => a.cluster_label === label).length;
  return '- ' + label + ' (' + count + ' articles)';
}).join('\n');

const prompt = 'Write a PRISMA 2020 systematic review protocol report based on the following data. Be scientific, concise, and professional. Write in English.\n\nRESEARCH QUESTION: ' + question + '\n\nINCLUSION/EXCLUSION CRITERIA: ' + criteria + '\n\nSEARCH STATISTICS:\n- Databases: ' + sources.join(', ') + '\n- Total records retrieved: ' + totalBeforeDedup + '\n- Duplicates removed: ' + duplicatesRemoved + '\n- Records after deduplication: ' + total + '\n- After AI screening: Included=' + included + ' Excluded=' + excluded + ' Uncertain=' + maybe + '\n- Full text available: ' + with_pdf + '\n\nTHEMATIC CLUSTERS:\n' + (clusterSummary || 'No clusters') + '\n\nTOP INCLUDED ARTICLES:\n' + (topIncluded || 'None') + '\n\nWrite these sections (use ## for headers):\n1. Background\n2. Search Strategy\n3. Inclusion and Exclusion Criteria\n4. Results Summary\n5. Thematic Analysis\n6. Limitations\n7. Next Steps for Manual Review';

// Extract search equations from article metadata
const pubmed_query = (articles[0] && articles[0].pubmed_query) || '';
const openalex_query = (articles[0] && articles[0].openalex_query) || '';
const crossref_query = (articles[0] && articles[0].crossref_query) || '';

console.log('PRISMA prompt built: ' + prompt.length + ' chars');
console.log('Search queries found: PubMed=' + (pubmed_query ? 'yes' : 'no') + ' OpenAlex=' + (openalex_query ? 'yes' : 'no') + ' Crossref=' + (crossref_query ? 'yes' : 'no'));

return [{ json: {
  prompt, articles, stats: { total, included, excluded, maybe, with_pdf, sources, clusters, total_before_dedup: totalBeforeDedup, duplicates_removed: duplicatesRemoved },
  ris, xlsx_base64, outputFolder, question, criteria,
  total, included, excluded, maybe, with_pdf, sources, clusters, totalBeforeDedup, duplicatesRemoved,
  pubmed_query, openalex_query, crossref_query
}}];

// ─── Generate PRISMA HTML Report & Save All Files ───
const fs = require('fs');
const path = require('path');

const ollamaResp = $input.all()[0].json;
const prev = $('Build PRISMA Prompt').first().json;

const prismaText = ollamaResp.response || 'Unable to generate narrative sections. Please review the statistics below.';
const articles = prev.articles || [];
const pStats = prev.stats || {};
const ris = prev.ris || '';
const xlsx_base64 = prev.xlsx_base64 || '';
const outputFolder = prev.outputFolder || '/desktop/review ultralab';
const question = prev.question || '';
const criteria = prev.criteria || '';

const total = prev.total || 0;
const included = prev.included || 0;
const excluded = prev.excluded || 0;
const maybe = prev.maybe || 0;
const with_pdf = prev.with_pdf || 0;
const sources = prev.sources || [];
const clusters = prev.clusters || [];
const totalBeforeDedup = prev.totalBeforeDedup || total;
const duplicatesRemoved = prev.duplicatesRemoved || 0;
const pubmed_query = prev.pubmed_query || '';
const openalex_query = prev.openalex_query || '';
const crossref_query = prev.crossref_query || '';
const dateStr = new Date().toISOString().split('T')[0];

// ─── Parse LLM text to HTML ───
function textToHtml(text) {
  return text.split('\n').map(line => {
    const l = line.trim();
    if (!l) return '';
    if (l.startsWith('## ')) return '<h2>' + l.substring(3) + '</h2>';
    if (l.startsWith('### ')) return '<h3>' + l.substring(4) + '</h3>';
    if (l.startsWith('- ')) return '<li>' + l.substring(2) + '</li>';
    if (l.startsWith('* ')) return '<li>' + l.substring(2) + '</li>';
    return '<p>' + l + '</p>';
  }).join('\n');
}

// ─── Cluster rows ───
const clusterRows = clusters.map(label => {
  const count = articles.filter(a => a.cluster_label === label).length;
  const inc = articles.filter(a => a.cluster_label === label && a.screening_decision === 'Include').length;
  return '<tr><td>' + label + '</td><td style="text-align:center">' + count + '</td><td style="text-align:center">' + inc + '</td></tr>';
}).join('\n');

// ─── Source rows ───
const sourceRows = sources.map(s => {
  const count = articles.filter(a => a.source === s).length;
  return '<tr><td>' + s + '</td><td style="text-align:center">' + count + '</td></tr>';
}).join('\n');

// ─── Top included articles ───
const topArticles = articles
  .filter(a => a.screening_decision === 'Include')
  .sort((a, b) => (b.score || 0) - (a.score || 0))
  .slice(0, 15)
  .map(a => '<tr><td>' + (a.title || '').substring(0, 80) + '</td><td>' + (Array.isArray(a.authors) ? a.authors.slice(0, 3).join(', ') : '') + '</td><td style="text-align:center">' + (a.year || '') + '</td><td style="text-align:center">' + (a.score || '') + '</td><td>' + (a.cluster_label || '') + '</td></tr>')
  .join('\n');

// ─── Build complete HTML ───
const html = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>PRISMA 2020 - Systematic Review Report</title>
<style>
  @page { size: A4; margin: 2cm; }
  body { font-family: 'Segoe UI', Calibri, Arial, sans-serif; max-width: 900px; margin: 0 auto; padding: 40px 20px; color: #333; line-height: 1.6; }
  .cover { text-align: center; padding: 80px 0 60px 0; border-bottom: 3px solid #4472C4; margin-bottom: 40px; }
  .cover h1 { color: #4472C4; font-size: 2.5em; margin-bottom: 10px; }
  .cover .subtitle { color: #666; font-size: 1.3em; margin-bottom: 30px; }
  .cover .question { font-style: italic; font-size: 1.1em; color: #333; max-width: 700px; margin: 0 auto; padding: 20px; background: #f5f7fa; border-radius: 8px; }
  .cover .date { color: #999; font-size: 0.9em; margin-top: 30px; }
  h1 { color: #4472C4; border-bottom: 2px solid #4472C4; padding-bottom: 8px; margin-top: 40px; }
  h2 { color: #2e5a8e; margin-top: 30px; }
  h3 { color: #555; }
  table { width: 100%; border-collapse: collapse; margin: 15px 0 25px 0; }
  th { background: #4472C4; color: white; padding: 10px 12px; text-align: left; font-weight: 600; }
  td { padding: 8px 12px; border-bottom: 1px solid #e0e0e0; }
  tr:nth-child(even) { background: #f8f9fa; }
  tr:hover { background: #e8ecf1; }
  .flow-table td, .flow-table th { border: 1px solid #ccc; }
  .phase-id { background: #4472C4; color: white; font-weight: bold; text-align: center; }
  .phase-screen { background: #FFA500; color: white; font-weight: bold; text-align: center; }
  .phase-include { background: #00B050; color: white; font-weight: bold; text-align: center; }
  .stat-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(180px, 1fr)); gap: 15px; margin: 20px 0; }
  .stat-card { background: #f5f7fa; border-radius: 8px; padding: 15px; text-align: center; border-left: 4px solid #4472C4; }
  .stat-card.green { border-left-color: #00B050; }
  .stat-card.orange { border-left-color: #FFA500; }
  .stat-card.red { border-left-color: #FF0000; }
  .stat-card .number { font-size: 2em; font-weight: bold; color: #333; }
  .stat-card .label { font-size: 0.85em; color: #666; margin-top: 5px; }
  .screening-include { color: #00B050; font-weight: bold; }
  .screening-maybe { color: #FFA500; font-weight: bold; }
  .screening-exclude { color: #FF0000; font-weight: bold; }
  .footer { text-align: center; margin-top: 60px; padding-top: 20px; border-top: 1px solid #ddd; color: #999; font-size: 0.85em; }
  li { margin-bottom: 5px; }
  @media print { body { padding: 0; } .cover { page-break-after: always; } }
</style>
</head>
<body>

<!-- COVER PAGE -->
<div class="cover">
  <h1>PRISMA 2020</h1>
  <div class="subtitle">Systematic Review Protocol Report</div>
  <div class="question">${question || 'Systematic Review'}</div>
  <div class="date">Generated by UltraLab on ${dateStr}</div>
</div>

<!-- PRISMA FLOW DIAGRAM -->
<h1>PRISMA 2020 Flow Diagram</h1>
<table class="flow-table">
  <tr><td class="phase-id" rowspan="5">IDENTIFICATION</td><td>Records identified through database searching</td><td style="text-align:center;font-weight:bold">${totalBeforeDedup}</td></tr>
  ${sourceRows ? sources.map(s => '<tr><td>&nbsp;&nbsp;&bull; ' + s + '</td><td style="text-align:center">' + articles.filter(a => a.source === s).length + '</td></tr>').join('\n') : ''}
  <tr><td>Duplicate records removed</td><td style="text-align:center;font-weight:bold">${duplicatesRemoved}</td></tr>
  <tr><td class="phase-screen" rowspan="4">SCREENING</td><td>Records after deduplication</td><td style="text-align:center;font-weight:bold">${total}</td></tr>
  <tr><td>Records screened (AI pre-screening)</td><td style="text-align:center">${total}</td></tr>
  <tr><td>Records excluded by AI</td><td style="text-align:center;font-weight:bold;color:#FF0000">${excluded}</td></tr>
  <tr><td>Records uncertain (manual review needed)</td><td style="text-align:center;font-weight:bold;color:#FFA500">${maybe}</td></tr>
  <tr><td class="phase-include" rowspan="2">INCLUDED</td><td>Studies included in pre-screening</td><td style="text-align:center;font-weight:bold;color:#00B050">${included}</td></tr>
  <tr><td>Full-text articles available (open access)</td><td style="text-align:center">${with_pdf}</td></tr>
</table>

<!-- SEARCH EQUATIONS -->
<h1>Search Equations</h1>
<p>The following search equations were generated by AI and used to query each academic database:</p>
<table>
  <tr><th style="width:15%">Database</th><th>Search Equation</th></tr>
  <tr><td><strong>PubMed</strong></td><td><code>${pubmed_query || 'N/A'}</code></td></tr>
  <tr><td><strong>OpenAlex</strong></td><td><code>${openalex_query || 'N/A'}</code></td></tr>
  <tr><td><strong>Crossref</strong></td><td><code>${crossref_query || 'N/A'}</code></td></tr>
</table>
<p><em>Note: Search equations are generated with temperature=0 for reproducibility.</em></p>

<!-- RANKING CRITERIA -->
<h1>Relevance Ranking Criteria</h1>
<p>Each article was scored from 0 to 100 by the AI model based on the following criteria:</p>
<ul>
  <li><strong>Relevance to research question:</strong> How closely the article title and abstract match the research question</li>
  <li><strong>Keyword alignment:</strong> Presence of key terms from the research question in the article</li>
  <li><strong>Methodological fit:</strong> Whether the study design and population match the inclusion criteria</li>
  <li><strong>Recency and impact:</strong> Publication year and journal relevance</li>
</ul>
<p>The AI was instructed: <em>&quot;Score the relevance of each article for the research question. Provide a score 0-100 with a one-sentence justification.&quot;</em></p>
<p>Individual ranking justifications are available in the Excel export file (column &quot;Critere Ranking&quot;).</p>

<!-- STATISTICS -->
<h1>Pre-screening Summary</h1>
<div class="stat-grid">
  <div class="stat-card"><div class="number">${total}</div><div class="label">Total Articles</div></div>
  <div class="stat-card green"><div class="number">${included}</div><div class="label">Inclusion probable</div></div>
  <div class="stat-card orange"><div class="number">${maybe}</div><div class="label">Uncertain</div></div>
  <div class="stat-card red"><div class="number">${excluded}</div><div class="label">Non-inclusion probable</div></div>
</div>

<p><strong>Criteria:</strong> ${criteria || 'No specific criteria provided.'}</p>

<!-- THEMATIC CLUSTERS -->
<h1>Thematic Clusters</h1>
<table>
  <tr><th>Cluster</th><th style="text-align:center">Articles</th><th style="text-align:center">Included</th></tr>
  ${clusterRows || '<tr><td colspan="3">No clusters identified</td></tr>'}
</table>

<!-- TOP INCLUDED ARTICLES -->
<h1>Top Included Articles</h1>
<table>
  <tr><th>Title</th><th>Authors</th><th style="text-align:center">Year</th><th style="text-align:center">Score</th><th>Cluster</th></tr>
  ${topArticles || '<tr><td colspan="5">No articles included</td></tr>'}
</table>

<!-- LLM NARRATIVE -->
<h1>Detailed Report</h1>
${textToHtml(prismaText)}

<!-- FOOTER -->
<div class="footer">
  <p>This report was generated automatically by <strong>UltraLab Systematic Review</strong>.</p>
  <p>AI pre-screening results are indicative and require human validation.</p>
  <p>PRISMA 2020 guidelines: Page MJ et al. BMJ 2021;372:n71</p>
</div>

</body>
</html>`;

console.log('PRISMA HTML generated: ' + html.length + ' chars');

// ─── Save all files to output folder ───
let savedFiles = [];
try {
  fs.mkdirSync(outputFolder, { recursive: true });

  // Save PRISMA HTML report
  fs.writeFileSync(path.join(outputFolder, 'PRISMA_Report.html'), html, 'utf-8');
  savedFiles.push('PRISMA_Report.html');

  // Save RIS file
  if (ris && ris.length > 0) {
    fs.writeFileSync(path.join(outputFolder, 'articles.ris'), ris, 'utf-8');
    savedFiles.push('articles.ris');
  }

  // Save XLSX file
  if (xlsx_base64 && xlsx_base64.length > 0) {
    fs.writeFileSync(path.join(outputFolder, 'pre_screening.xlsx'), Buffer.from(xlsx_base64, 'base64'));
    savedFiles.push('pre_screening.xlsx');
  }

  console.log('Files saved to ' + outputFolder + ': ' + savedFiles.join(', '));
} catch(e) {
  console.log('File save error: ' + e.message + ' - files will be in response data only');
}

return [{
  json: {
    prisma_protocol: prismaText,
    prisma_html: html,
    prisma_stats: pStats,
    articles,
    ris,
    xlsx_base64,
    output_folder: outputFolder,
    question,
    saved_files: savedFiles
  }
}];
